public:
    Transaction(Database& d) : db(d) { db.begin(); }
    ~Transaction() {
        if (!committed) db.rollback();  // ✅ Default rollback
    }
    void commit() {
        db.commit();
        committed = true;  // ✅ Mark as committed
    }
};

void updateDB(Database& db) {
