    auto ptr = std::make_shared<ThrowsInConstructor>();
} catch (...) {
    // No leak: make_shared freed the allocation
}

try {
    // ❌ Potential leak if exception between allocations
    std::shared_ptr<ThrowsInConstructor> ptr(new ThrowsInConstructor());
